change_2_template_verdict_badge.to:
// Verdict badge glyph mapping (paired with class-driven color via .vb-${verdict})
  const badgeGlyphs = {
    'standard_physics': '\u2713',  // ✓
    'recycled':         '\u21BB',  // ↻
    'falsified':        '\u2715',  // ✕
    'unfalsifiable':    '\u25CC',  // ◌
    'pending':          '\u29D6',  // ⧖ (hourglass)
  };
  const badgeGlyph = badgeGlyphs[verdict] || badgeGlyphs['pending'];
  ...
  html += ` <span class="verdict-badge vb-${verdict}" style="margin-left:8px"><span class="vb-glyph" aria-hidden="true">${badgeGlyph}</span>${escapeHtml(verdictLabel)}</span>`;

assertions.test_pseudocode:
const html = fs.readFileSync('docs/index.html', 'utf8');
const verdictBadgeRE = /<span class="verdict-badge vb-[a-z_]+">/g;
const withGlyphRE = /<span class="verdict-badge vb-[a-z_]+"[^>]*>\s*<span class="vb-glyph" aria-hidden="true">/g;
const total = (html.match(verdictBadgeRE) || []).length;
const withGlyph = (html.match(withGlyphRE) || []).length;
assert(total > 50, 'expected 90+ verdict-badge spans (post-class-migration); got ' + total);
assert(withGlyph === total, 'every .verdict-badge.vb-* must contain a <span class="vb-glyph" aria-hidden="true"> child; got ' + withGlyph + ' of ' + total);

const html = fs.readFileSync('docs/index.html', 'utf8');
const inlineHexRE = /class="verdict-badge"[^>]*style="[^"]*background:#[A-Fa-f0-9]{3,6}/g;
const leftover = html.match(inlineHexRE);
assert(!leftover, 'no .verdict-badge may carry inline-style hex backgrounds (must use vb-* class). Found: ' + (leftover ? leftover.length : 0));

const css = fs.readFileSync('build-scripts/generate-html.js', 'utf8');
assert(css.match(/\.tab-btn\{[^}]*min-height:44px/) || css.match(/@media\(max-width:600px\)\{\.tab-btn\{[^}]*min-height:44px/), 'mobile .tab-btn rule must pin min-height:44px');
assert(css.match(/\.toc a\{[^}]*min-height:44px/), '.toc a rule must pin min-height:44px');
assert(css.match(/\.skip-link\{[^}]*min-height:44px/), '.skip-link rule must pin min-height:44px');
assert(css.match(/\.win-anchor\{[^}]*min-height:44px/), '.win-anchor rule must pin min-height:44px');

const css = fs.readFileSync('build-scripts/generate-html.js', 'utf8');
const media = css.match(/@media\(max-width:720px\)\{\.stacked-card-table[\s\S]+?\}\}/);
assert(media, '.stacked-card-table @media(max-width:720px) block must be present');
assert(media[0].includes('thead{display:none}'), 'stacked-card-table mobile must hide thead');
assert(media[0].includes('tr{display:block'), 'stacked-card-table mobile rows must be block-level');
assert(media[0].includes('::before'), 'stacked-card-table mobile cells must use ::before data-label pseudo-element');

const sec = fs.readFileSync('data/sections.json', 'utf8');
const f5regression = sec.match(/background:\s*#f5f5f5/);
const whiteRegression = sec.match(/background:\s*#fff["\s;]/);
assert(!f5regression, 'data/sections.json must not contain background:#f5f5f5 (integrity-flagged hardcoded light panel — use var(--code-bg))');
assert(!whiteRegression, 'data/sections.json must not contain background:#fff (integrity-flagged hardcoded light panel — use var(--card-bg))');
